import React, { useState } from 'react';

function Login({ onLogin }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    if (!username.trim() || !password) {
      setError('Please fill in all fields.');
      return;
    }
    setLoading(true);
    try {
      const res = await fetch('/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password }),
      });
      if (!res.ok) throw new Error('Invalid username or password.');
      const data = await res.json();
      localStorage.setItem('token', data.token);
      onLogin(data);
    } catch (err) {
      setError(err.message || 'Something went wrong.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#0f1117] flex items-center justify-center px-4">
      <div className="bg-[#1a1f2e] border border-white/10 rounded-2xl p-10 w-full max-w-sm">

        {/* Brand */}
        <div className="flex items-center gap-2 mb-8">
          <span className="w-2.5 h-2.5 rounded-full bg-[#4f7cff]" />
          <span className="text-white font-semibold text-[15px] tracking-tight">AdminPanel</span>
        </div>

        <h2 className="text-[22px] font-semibold text-white mb-1">Welcome back</h2>
        <p className="text-sm text-white/45 mb-8">Sign in to your account to continue</p>

        <form onSubmit={handleSubmit} className="flex flex-col gap-3.5">
          {/* Username */}
          <div className="flex flex-col gap-1.5">
            <label className="text-[11px] font-medium text-white/50 uppercase tracking-wide">
              Username
            </label>
            <input
              type="text"
              value={username}
              onChange={e => setUsername(e.target.value)}
              placeholder="Enter username"
              autoComplete="username"
              className="bg-white/5 border border-white/12 rounded-[9px] px-3.5 py-2.5 text-sm
                text-white placeholder:text-white/25 outline-none transition-colors
                focus:border-[#4f7cff] focus:bg-[#4f7cff]/7"
            />
          </div>

          {/* Password */}
          <div className="flex flex-col gap-1.5">
            <label className="text-[11px] font-medium text-white/50 uppercase tracking-wide">
              Password
            </label>
            <div className="relative">
              <input
                type={showPassword ? 'text' : 'password'}
                value={password}
                onChange={e => setPassword(e.target.value)}
                placeholder="Enter password"
                autoComplete="current-password"
                className="w-full bg-white/5 border border-white/12 rounded-[9px] px-3.5 py-2.5
                  pr-14 text-sm text-white placeholder:text-white/25 outline-none transition-colors
                  focus:border-[#4f7cff] focus:bg-[#4f7cff]/7"
              />
              <button
                type="button"
                onClick={() => setShowPassword(v => !v)}
                className="absolute right-3.5 top-1/2 -translate-y-1/2 text-xs text-white/35
                  hover:text-white/70 transition-colors"
              >
                {showPassword ? 'Hide' : 'Show'}
              </button>
            </div>
            <a href="#" className="self-end text-xs text-[#4f7cff] hover:text-[#7fa4ff] transition-colors">
              Forgot password?
            </a>
          </div>

          {/* Error */}
          {error && (
            <p className="text-xs text-[#f09595]">{error}</p>
          )}

          {/* Submit */}
          <button
            type="submit"
            disabled={loading}
            className="mt-2 bg-[#4f7cff] hover:bg-[#3d6be0] active:scale-[0.98] disabled:opacity-70
              disabled:cursor-not-allowed text-white font-semibold text-sm py-2.5 rounded-[9px]
              transition-all"
          >
            {loading ? 'Signing in...' : 'Sign in'}
          </button>
        </form>

        {/* Divider */}
        <div className="flex items-center gap-2.5 my-5">
          <div className="flex-1 h-px bg-white/10" />
          <span className="text-xs text-white/30">or</span>
          <div className="flex-1 h-px bg-white/10" />
        </div>

        
       
      </div>
    </div>
  );
}

export default Login;
